export const convertPropsToClasses = ({ bordered, feedback, size, }) => {
    let classes = '';
    if (bordered) {
        classes = `${classes} modus-wc-textarea-bordered`;
    }
    if (feedback) {
        classes = `${classes} modus-wc-input--${feedback.level}`;
    }
    if (size) {
        classes = `${classes} modus-wc-textarea-${size}`;
    }
    return classes.trim();
};
